SELECT fl.id, fl.task_type AS taskType, fl.algorithm_type AS algorithmType, fl.federated_type AS federatedType, fl.task_name AS taskName, fl.project_id AS projectId, flt.task_id AS taskId, flt.task_state AS taskState, flt.current_round AS currentRound, flt.total_rounds AS totalRounds, flt.accuracy, flt.loss, flt.result_rows AS resultRows, flt.create_date AS createDate FROM federated_learning fl INNER JOIN federated_learning_task flt ON fl.id = flt.fl_id WHERE flt.is_del = 0
AND fl.task_name LIKE CONCAT('%', #{taskName}, '%')
AND fl.task_type = #{taskType}
AND fl.algorithm_type = #{algorithmType}
AND flt.task_state = #{taskState}
AND fl.project_id = #{projectId}
AND flt.create_date >= #{startDate}
AND flt.create_date <= #{endDate}
ORDER BY flt.create_date DESC LIMIT #{offset}, #{pageSize}

SELECT COUNT(fl.id)
FROM
    federated_learning fl
INNER JOIN federated_learning_task flt ON fl.id = flt.fl_id
WHERE flt.is_del = 0

    AND fl.task_name LIKE CONCAT('%', #{taskName}, '%')


    AND fl.task_type = #{taskType}


    AND fl.algorithm_type = #{algorithmType}


    AND flt.task_state = #{taskState}


    AND fl.project_id = #{projectId}


    AND flt.create_date >= #{startDate}


    AND flt.create_date <= #{endDate}

SELECT fl.id, fl.task_name AS modelName, fl.algorithm_type AS algorithmType, fl.project_id AS projectId, fl.model_path AS modelPath, flt.task_id AS taskId, flt.accuracy, flt.loss, flt.metrics, flt.create_date AS createDate FROM federated_learning fl INNER JOIN federated_learning_task flt ON fl.id = flt.fl_id WHERE fl.task_type = 1 AND flt.task_state = 1 AND flt.is_del = 0
AND fl.algorithm_type = #{algorithmType}
AND fl.project_id = #{projectId}
ORDER BY flt.create_date DESC LIMIT #{offset}, #{pageSize}

SELECT COUNT(fl.id) FROM federated_learning fl INNER JOIN federated_learning_task flt ON fl.id = flt.fl_id WHERE fl.task_type = 1 AND flt.task_state = 1 AND flt.is_del = 0
AND fl.algorithm_type = #{algorithmType}
AND fl.project_id = #{projectId}
